//! SVG icon components (lucide-style).
use leptos::prelude::*;

#[must_use]
#[component]
pub fn Icon(name: &'static str, #[prop(optional, into)] class_name: String) -> impl IntoView {
    let svg = match name {
        "search" => SEARCH_SVG,
        "send" => SEND_SVG,
        "mic" => MIC_SVG,
        "paperclip" => PAPERCLIP_SVG,
        "smile" => SMILE_SVG,
        "more-horizontal" => MORE_HORIZ_SVG,
        "more-vertical" => MORE_VERTICAL_SVG,
        "x" => X_SVG,
        "check" => CHECK_SVG,
        "check-check" => CHECK_CHECK_SVG,
        "users" => USERS_SVG,
        "settings" => SETTINGS_SVG,
        "log-out" => LOG_OUT_SVG,
        "lock" => LOCK_SVG,
        "shield" => SHIELD_SVG,
        "bell" => BELL_SVG,
        "bell-off" => BELL_OFF_SVG,
        "moon" => MOON_SVG,
        "sun" => SUN_SVG,
        "user" => USER_SVG,
        "chevron-left" => CHEVRON_LEFT_SVG,
        "chevron-right" => CHEVRON_RIGHT_SVG,
        "edit" => EDIT_SVG,
        "trash" => TRASH_SVG,
        "reply" => REPLY_SVG,
        "smartphone" => SMARTPHONE_SVG,
        "monitor" => MONITOR_SVG,
        "tablet" => TABLET_SVG,
        "play" => PLAY_SVG,
        "pause" => PAUSE_SVG,
        "music" => MUSIC_SVG,
        "globe" => GLOBE_SVG,
        "qr-code" => QR_SVG,
        "copy" => COPY_SVG,
        "plus" => PLUS_SVG,
        "info" => INFO_SVG,
        "arrow-left" => ARROW_LEFT_SVG,
        "alert-circle" => ALERT_CIRCLE_SVG,
        "alert-triangle" => ALERT_TRIANGLE_SVG,
        "help-circle" => HELP_CIRCLE_SVG,
        "loader" => LOADER_SVG,
        "refresh-cw" => REFRESH_CW_SVG,
        "check-circle" => CHECK_CIRCLE_SVG,
        "x-circle" => X_CIRCLE_SVG,
        "upload" => UPLOAD_SVG,
        "key" => KEY_SVG,
        "message-square" => MESSAGE_SQUARE_SVG,
        "image" => IMAGE_SVG,
        "file" => FILE_SVG,
        "file-text" => FILE_TEXT_SVG,
        "film" => FILM_SVG,
        "pin" => PIN_SVG,
        "archive" => ARCHIVE_SVG,
        "pencil" => PENCIL_SVG,
        "download" => DOWNLOAD_SVG,
        "forward" => FORWARD_SVG,
        "camera" => CAMERA_SVG,
        "user-plus" => USER_PLUS_SVG,
        "mic-off" => MIC_OFF_SVG,
        "laptop" => LAPTOP_SVG,
        "ticket" => TICKET_SVG,
        "palette" => PALETTE_SVG,
        "shield-check" => SHIELD_CHECK_SVG,
        "shield-alert" => SHIELD_ALERT_SVG,
        _ => "<svg xmlns='http://www.w3.org/2000/svg' width='24' height='24' viewBox='0 0 24 24'/>",
    };
    // Use inner_html to inject raw SVG. The `data-icon` attribute lets a
    // single CSS rule in main.css (`[data-icon] > svg { width:100%; height:100% }`)
    // force the SVG to scale to the span's tailwind-set size — otherwise the
    // hardcoded `width="24" height="24"` inside each SVG overrides `h-3 w-3`.
    view! { <span class=class_name data-icon="" inner_html=svg></span> }
}

